import time
from typing import Any, Optional, Tuple
from threading import Lock


class TTLCache:
    def __init__(self, default_ttl: float = 300.0):
        self.default_ttl = default_ttl
        self._store: dict[str, Tuple[Any, float]] = {}  # key -> (value, expires_at)
        self._lock = Lock()

    def get(self, key: str) -> Optional[Any]:
        with self._lock:
            if key in self._store:
                value, expires_at = self._store[key]
                if time.time() < expires_at:
                    return value
                del self._store[key]
            return None

    def set(self, key: str, value: Any, ttl: Optional[float] = None) -> None:
        with self._lock:
            expires_at = time.time() + (ttl if ttl is not None else self.default_ttl)
            self._store[key] = (value, expires_at)

    def invalidate(self, prefix: str) -> int:
        """Remove all entries whose keys start with prefix."""
        with self._lock:
            keys_to_remove = [k for k in self._store if k.startswith(prefix)]
            for k in keys_to_remove:
                del self._store[k]
            return len(keys_to_remove)

    def clear(self) -> None:
        with self._lock:
            self._store.clear()

    @property
    def size(self) -> int:
        with self._lock:
            return len(self._store)

import httpx
from typing import Any, Dict, Optional
from client.cache import TTLCache


class APIClient:
    def __init__(self, base_url: str, api_key: str, cache_ttl: float = 300.0):
        self.base_url = base_url.rstrip('/')
        self.headers = {'Authorization': f'Bearer {api_key}'}
        self.cache = TTLCache(default_ttl=cache_ttl)

    def _cache_key(self, path: str, params: Optional[Dict] = None) -> str:
        key = path
        if params:
            sorted_params = '&'.join(f'{k}={v}' for k, v in sorted(params.items()))
            key = f'{path}?{sorted_params}'
        return key

    def get(self, path: str, params: Optional[Dict] = None) -> Any:
        key = self._cache_key(path, params)
        cached = self.cache.get(key)
        if cached is not None:
            return cached
        resp = httpx.get(f'{self.base_url}{path}', headers=self.headers, params=params)
        resp.raise_for_status()
        result = resp.json()
        self.cache.set(key, result)
        return result

    def post(self, path: str, data: Dict) -> Any:
        resp = httpx.post(f'{self.base_url}{path}', headers=self.headers, json=data)
        resp.raise_for_status()
        self.cache.invalidate(path)
        return resp.json()

    def put(self, path: str, data: Dict) -> Any:
        resp = httpx.put(f'{self.base_url}{path}', headers=self.headers, json=data)
        resp.raise_for_status()
        self.cache.invalidate(path)
        return resp.json()

    def delete(self, path: str) -> None:
        resp = httpx.delete(f'{self.base_url}{path}', headers=self.headers)
        resp.raise_for_status()
        self.cache.invalidate(path)
